PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" varchar not null, "queue" varchar not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "businesses" ("id" integer primary key autoincrement not null, "user_id" integer not null, "name" varchar not null, "category" varchar, "contact" varchar, "address" text, "description" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "role" varchar not null default ('owner'), "business_id" integer, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, foreign key("business_id") references "businesses"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "products" ("id" integer primary key autoincrement not null, "business_id" integer not null, "name" varchar not null, "cost_price" numeric not null, "sell_price" numeric not null, "stock" integer not null default '0', "min_stock" integer not null default '5', "created_at" datetime, "updated_at" datetime, foreign key("business_id") references "businesses"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transactions" ("id" integer primary key autoincrement not null, "business_id" integer not null, "user_id" integer not null, "invoice_number" varchar not null, "total_amount" numeric not null, "total_cost" numeric not null, "payment_amount" numeric not null, "change_amount" numeric not null, "notes" text, "created_at" datetime, "updated_at" datetime, foreign key("business_id") references "businesses"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transaction_details" ("id" integer primary key autoincrement not null, "transaction_id" integer not null, "product_id" integer not null, "product_name" varchar not null, "quantity" integer not null, "cost_price" numeric not null, "sell_price" numeric not null, "subtotal" numeric not null, "created_at" datetime, "updated_at" datetime, foreign key("transaction_id") references "transactions"("id") on delete cascade, foreign key("product_id") references "products"("id") on delete cascade);
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "cache_expiration_index" on "cache" ("expiration");
CREATE INDEX "cache_locks_expiration_index" on "cache_locks" ("expiration");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE INDEX "failed_jobs_connection_queue_failed_at_index" on "failed_jobs" ("connection", "queue", "failed_at");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE UNIQUE INDEX "transactions_invoice_number_unique" on "transactions" ("invoice_number");
COMMIT;
